1	import prisma from 'prisma/prisma';
2	import { PlayerType } from 'prisma/zod/schemas/models/Player.schema';
3	import { PlayerLoginWhereUniqueInputObjectSchema } from 'prisma/zod/schemas/objects/PlayerLoginWhereUniqueInput.schema';
4	import { PlayerWhereUniqueInputObjectSchema } from 'prisma/zod/schemas/objects/PlayerWhereUniqueInput.schema';
5	import z from 'zod';
6	
7	import { isPrismaNotFoundError } from '@/lib/prismaErrors';
8	import { FamilyTreeNodeType, PlayerDataType, PlayerFormType } from '@/types';
9	import {
10	    PlayerCreateOneStrictSchema,
11	    type PlayerCreateWriteInput,
12	    PlayerCreateWriteInputSchema,
13	    PlayerUpdateOneStrictSchema,
14	    type PlayerUpdateWriteInput,
15	    PlayerUpdateWriteInputSchema,
16	} from '@/types/PlayerStrictSchema';
17	import { PointsSchema, type PointsValue } from '@/types/Points';
18	
19	export type PlayerDisplayType = Omit<PlayerType, 'name'> & { name: string };
20	export type PlayerDataDisplayType = Omit<PlayerDataType, 'name'> & { name: string };
21	
22	class PlayerService {
23	    /**
24	     * Gets the display name for a player.
25	     *
26	     * If the player is anonymous (i.e., the `anonymous` flag is `true`),
27	     * returns a generic name with the player ID. Otherwise, returns the
28	     * player's trimmed name, falling back to a generic name if the name is
29	     * empty or null. A `null` value for `anonymous` is treated as not anonymous
30	     * (equivalent to `false`).
31	     *
32	     * @param player - The player object containing id, name, and anonymous flag
33	     * @param player.id - The unique identifier for the player
34	     * @param player.name - The player's name, can be null
35	     * @param player.anonymous - Whether the player is anonymous; `true` marks
36	     * the player as anonymous, while `false` or a `null` value are treated as
37	     * not anonymous
38	     * @returns The display name for the player
39	     */
40	    private getDisplayName(player: { id: number; name: string | null; anonymous: boolean | null }) {
41	        if (player.anonymous) {
42	            return `Player ${player.id}`;
43	        }
44	
45	        return player.name?.trim() ?? `Player ${player.id}`;
46	    }
47	
48	    /**
49	    * Sanitizes a player object by replacing its name with a display name.
50	    *
51	    * @template T - The player object type extending an object with `id`,
52	    * `name`, and `anonymous` properties.
53	    * @param player - The player object to sanitize.
54	    * @returns A new object with the same properties as the input player, but
55	    * with the `name` property replaced by the display name (guaranteed to be a
56	    * string, not null).
57	    */
58	    private sanitizePlayerName<T extends { id: number; name: string | null; anonymous: boolean | null }>(
59	        player: T,
60	    ): Omit<T, 'name'> & { name: string } {
61	        return {
62	            ...player,
63	            name: this.getDisplayName(player),
64	        };
65	    }
66	
67	    /**
68	     * Get a single player by id
69	     * @param id The numeric ID for the player
70	     * @returns A promise that resolves to the player or undefined if none was
71	     * found
72	     */
73	    async getById(id: number): Promise<PlayerDisplayType | null> {
74	        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
75	        const player = await prisma.player.findUnique({ where });
76	        return player ? this.sanitizePlayerName(player) : null;
77	    }
78	
79	    /**
80	     * Get a single player by id, including email data (account email and extra emails).
81	     * @param id The numeric ID for the player
82	     * @returns A promise that resolves to the player with email data, or null if not found
83	     */
84	    async getDataById(id: number): Promise<PlayerDataDisplayType | null> {
85	        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
86	        const player = await prisma.player.findUnique({
87	            where,
88	            include: {
89	                extraEmails: {
90	                    orderBy: [
91	                        { verifiedAt: 'desc' },
92	                        { createdAt: 'desc' },
93	                    ],
94	                },
95	            },
96	        });
97	        if (!player) return null;
98	
99	        const { extraEmails, ...rest } = player;
100	        const accountEmail = (rest as { accountEmail?: string | null }).accountEmail ?? null;
101	        const playerData = {
102	            ...rest,
103	            accountEmail,
104	            extraEmails,
105	            firstResponded: null,
106	            lastResponded: null,
107	            firstPlayed: null,
108	            lastPlayed: null,
109	            gamesPlayed: 0,
110	            gamesWon: 0,
111	            gamesDrawn: 0,
112	            gamesLost: 0,
113	        } satisfies PlayerDataType;
114	
115	        return this.sanitizePlayerName(playerData);
116	    }
117	
118	    /**
119	     * Get a single player by login
120	     * @param login The login name
121	     * @returns A promise that resolves to the player or undefined if none was
122	     * found
123	     */
124	    async getByLogin(login: string): Promise<PlayerDisplayType | null> {
125	        const where = PlayerLoginWhereUniqueInputObjectSchema.parse({ login });
126	        const playerLogin = await prisma.playerLogin.findUnique({
127	            where,
128	            include: {
129	                player: true,
130	            },
131	        });
132	
133	        return playerLogin?.player ? this.sanitizePlayerName(playerLogin.player) : null;
134	    }
135	
136	    /**
137	     * Get the player corresponding to the given string. If idOrLogin is a
138	     * string then we check whether a player with the given login exists. If
139	     * it's a number then we look up the player with that id.
140	     * @param idOrLogin A string which may contain a player id or a login
141	     * @returns A promise resolving to the player identified by idOrLogin if
142	     * such a player exists, or undefined otherwise.
143	     */
144	    async getByIdOrLogin(idOrLogin: string): Promise<PlayerDisplayType | null> {
145	        if (!isNaN(Number(idOrLogin))) {
146	            return this.getById(Number(idOrLogin));
147	        } else {
148	            return this.getByLogin(idOrLogin);
149	        }
150	    }
151	
152	    /**
153	     * Get the player login corresponding to the given string. If idOrLogin is a
154	     * string then we check whether a player with the given login exists. If it's a
155	     * number then we look up the player with that id.
156	     * @param idOrLogin A string which may contain a player id or a login
157	     * @returns A string containing the login of the player identified by idOrLogin
158	     * if such a player exists, or undefined otherwise.
159	     */
160	    async getLogin(idOrLogin: string) {
161	        if (!isNaN(Number(idOrLogin))) {
162	            const playerLogin = await prisma.playerLogin.findFirst({
163	                where: {
164	                    playerId: Number(idOrLogin),
165	                },
166	                orderBy: {
167	                    login: 'asc',
168	                },
169	            });
170	            return playerLogin ? playerLogin.login : null;
171	        }
172	
173	        const where = PlayerLoginWhereUniqueInputObjectSchema.parse({ login: idOrLogin });
174	        const playerLogin = await prisma.playerLogin.findUnique({ where });
175	        return playerLogin ? playerLogin.login : null;
176	    }
177	
178	    /**
179	     * Retrieves the ID of a player based on the provided ID or login. If the
180	     * input is a valid number, it retrieves the player by ID. If the input is a
181	     * string, it retrieves the player by login.
182	     * @param idOrLogin - The ID or login of the player.
183	     * @returns A Promise that resolves to the player's ID if found, or null if
184	     * not found.
185	     * @throws If there is an error retrieving the player's ID.
186	     */
187	    async getId(idOrLogin: string) {
188	        if (!isNaN(Number(idOrLogin))) {
189	            const player = await this.getById(Number(idOrLogin));
190	            return player ? player.id : null;
191	        } else {
192	            const where = PlayerLoginWhereUniqueInputObjectSchema.parse({ login: idOrLogin });
193	            const playerLogin = await prisma.playerLogin.findUnique({ where });
194	            return playerLogin ? playerLogin.playerId : null;
195	        }
196	    }
197	
198	    /**
199	     * Retrieves the player with the next-lowest ID (i.e. the previous player by
200	     * ID).
201	     * @param playerId - The ID of the current player.
202	     * @returns A promise that resolves to the previous player if found, or null
203	     * if not found.
204	     */
205	    async getPrevious(playerId: number): Promise<PlayerDisplayType | null> {
206	        const id = z.coerce.number().int().min(1).parse(playerId);
207	
208	        const player = await prisma.player.findFirst({
209	            where: {
210	                id: {
211	                    lt: id,
212	                },
213	            },
214	            orderBy: {
215	                id: 'desc',
216	            },
217	        });
218	        return player ? this.sanitizePlayerName(player) : null;
219	    }
220	
221	    /**
222	     * Retrieves the player with the next-highest ID (i.e. the next player by
223	     * ID).
224	     * @param playerId - The ID of the current player.
225	     * @returns A promise that resolves to the next player if found, or null
226	     * if not found.
227	     */
228	    async getNext(playerId: number): Promise<PlayerDisplayType | null> {
229	        const id = z.coerce.number().int().min(1).parse(playerId);
230	
231	        const player = await prisma.player.findFirst({
232	            where: {
233	                id: {
234	                    gt: id,
235	                },
236	            },
237	            orderBy: {
238	                id: 'asc',
239	            },
240	        });
241	        return player ? this.sanitizePlayerName(player) : null;
242	    }
243	
244	    /**
245	     * Retrieves all players from the database with their outcomes and extra
246	     * emails.
247	     *
248	     * @param active - Optional filter to only return active players (those
249	     * without a finished date). Defaults to undefined for all players.
250	     * @returns A promise that resolves to an array of PlayerDataType objects
251	     * enriched with computed statistics including:
252	     *          - accountEmail: The player's account email address
253	     *          - firstResponded: The earliest gameDayId where the player responded
254	     *          - lastResponded: The latest gameDayId where the player responded
255	     *          - firstPlayed: The earliest gameDayId where the player earned points
256	     *          - lastPlayed: The latest gameDayId where the player earned points
257	     *          - gamesPlayed: Total number of games with recorded points
258	     *          - gamesWon: Number of games where the player earned 3 points
259	     *          - gamesDrawn: Number of games where the player earned 1 point
260	     *          - gamesLost: Number of games where the player earned 0 points
261	     * @throws Logs and re-throws any errors that occur during the database
262	     * query
263	     */
264	    async getAll(options?: { activeOnly?: boolean }): Promise<PlayerDataDisplayType[]> {
265	        const players = await prisma.player.findMany({
266	            where: options?.activeOnly ? { finished: null } : undefined,
267	            include: {
268	                outcomes: {
269	                    orderBy: {
270	                        gameDayId: 'desc',
271	                    },
272	                },
273	                extraEmails: {
274	                    orderBy: [
275	                        { verifiedAt: 'desc' },
276	                        { createdAt: 'desc' },
277	                    ],
278	                },
279	            },
280	        });
281	
282	        return players.map(({ outcomes, ...player }) => {
283	            const gamesResponded = outcomes.filter(outcome => outcome.response !== null);
284	            const gamesPlayed = outcomes.filter(outcome => outcome.points !== null);
285	
286	            const respondedGameDays = gamesResponded.map(outcome => outcome.gameDayId);
287	            const playedGameDays = gamesPlayed.map(outcome => outcome.gameDayId);
288	
289	            const accountEmail = (player as { accountEmail?: string | null }).accountEmail ?? null;
290	
291	            const playerWithComputedFields = {
292	                ...player,
293	                accountEmail,
294	                firstResponded: respondedGameDays.length > 0 ? Math.min(...respondedGameDays) : null,
295	                lastResponded: respondedGameDays.length > 0 ? Math.max(...respondedGameDays) : null,
296	                firstPlayed: playedGameDays.length > 0 ? Math.min(...playedGameDays) : null,
297	                lastPlayed: playedGameDays.length > 0 ? Math.max(...playedGameDays) : null,
298	                gamesPlayed: gamesPlayed.length,
299	                gamesWon: gamesPlayed.filter(outcome => outcome.points === 3).length,
300	                gamesDrawn: gamesPlayed.filter(outcome => outcome.points === 1).length,
301	                gamesLost: gamesPlayed.filter(outcome => outcome.points === 0).length,
302	            } satisfies PlayerDataType;
303	
304	            return this.sanitizePlayerName(playerWithComputedFields);
305	        });
306	    }
307	
308	    /**
309	     * Retrieves all player IDs and logins from the database.
310	     *
311	     * @returns {Promise<string[]>} A promise that resolves to an array of strings containing player IDs and logins.
312	     * @throws Will throw an error if there is an issue fetching the player data.
313	     */
314	    async getAllIdsAndLogins() {
315	        const players = await prisma.player.findMany({
316	            select: {
317	                id: true,
318	                logins: {
319	                    select: {
320	                        login: true,
321	                    },
322	                    orderBy: {
323	                        login: 'asc',
324	                    },
325	                },
326	            },
327	        });
328	        const idsAndLogins: string[] = [];
329	
330	        players.forEach((player) => {
331	            idsAndLogins.push(player.id.toString());
332	            player.logins.forEach((login) => {
333	                idsAndLogins.push(login.login);
334	            });
335	        });
336	
337	        return idsAndLogins;
338	    }
339	
340	    /**
341	     * Retrieves the form of a player for a given game day, based on their previous outcomes.
342	     * @param playerId - The ID of the player.
343	     * @param gameDayId - The ID of the game day to consider, or 0 for the latest.
344	     * @param history - The number of previous outcomes to consider.
345	     * @returns A promise that resolves to an array of outcomes with game days.
346	     */
347	    async getForm(
348	        playerId: number,
349	        gameDayId: number,
350	        history: number,
351	    ): Promise<PlayerFormType[]> {
352	        return prisma.outcome.findMany({
353	            where: {
354	                gameDayId: gameDayId !== 0 ? { lt: gameDayId } : {},
355	                playerId: playerId,
356	                points: {
357	                    not: null,
358	                },
359	            },
360	            orderBy: {
361	                gameDayId: 'desc',
362	            },
363	            take: history,
364	            include: {
365	                gameDay: true,
366	            },
367	        });
368	    }
369	
370	    /**
371	     * Retrieves the most recent outcome for a player, optionally filtered by
372	     * year and/or points value.
373	     *
374	     * @param playerId - The unique identifier of the player.
375	     * @param year - An optional year to limit the search range.
376	     * @param points - An optional points filter: if provided, only outcomes
377	     * with this points value will be returned. If not, the most recent outcome
378	     * with any non-null points value will be returned.
379	     * @returns A promise that resolves to the player's latest outcome including
380	     * its game day, or `null` if none is found.
381	     * @throws Will propagate any errors encountered during the retrieval
382	     * process.
383	     */
384	    async getLastResult(playerId: number, year?: number, points?: PointsValue): Promise<PlayerFormType | null> {
385	        const id = z.coerce.number().int().min(1).parse(playerId);
386	        const validatedPoints = PointsSchema.optional().parse(points);
387	
388	        return prisma.outcome.findFirst({
389	            where: {
390	                playerId: id,
391	                points: validatedPoints ?? { not: null },
392	                gameDay: {
393	                    date: {
394	                        gte: year ? new Date(Date.UTC(year, 0, 1)) : undefined,
395	                        lt: year ? new Date(Date.UTC(year + 1, 0, 1)) : undefined,
396	                    },
397	                },
398	            },
399	            orderBy: {
400	                gameDayId: 'desc',
401	            },
402	            include: {
403	                gameDay: true,
404	            },
405	            take: 1,
406	        });
407	    }
408	
409	    /**
410	     * Retrieves all the years that the given player has participated in any
411	     * way. That could be just responding to an invitation, going to the pub, or
412	     * playing a game of course.
413	     * @returns A promise that resolves to an array of distinct years: this will
414	     * always include 0 for 'all time' if there's at least one active year.
415	     * @throws An error if there is a failure.
416	     */
417	    async getYearsActive(playerId: number): Promise<number[]> {
418	        const id = z.coerce.number().int().min(1).parse(playerId);
419	
420	        const outcomes = await prisma.outcome.findMany({
421	            where: {
422	                playerId: id,
423	            },
424	            include: {
425	                gameDay: true,
426	            },
427	        });
428	        const years = outcomes.map(o => o.gameDay.date.getFullYear());
429	        const distinctYears = Array.from(new Set(years));
430	        if (distinctYears.length) {
431	            distinctYears.push(0);
432	        }
433	
434	        return distinctYears;
435	    }
436	
437	    /**
438	     * Creates a player from validated write input.
439	     * @param data - Player write payload.
440	     * @returns The created player row.
441	     */
442	    async create(data: PlayerCreateWriteInput): Promise<PlayerDisplayType> {
443	        const writeData = PlayerCreateWriteInputSchema.parse(data);
444	        const args = PlayerCreateOneStrictSchema.parse({ data: writeData });
445	        const player = await prisma.player.create(args);
446	        return this.sanitizePlayerName(player);
447	    }
448	
449	    /**
450	     * Updates an existing player by id from validated write input.
451	     * @param data - Player write payload including `id` and update fields.
452	     * @returns The updated player row.
453	     */
454	    async update(data: PlayerUpdateWriteInput): Promise<PlayerDisplayType> {
455	        const { id, ...updateData } = PlayerUpdateWriteInputSchema.parse(data);
456	        const args = PlayerUpdateOneStrictSchema.parse({
457	            where: { id },
458	            data: updateData,
459	        });
460	        const player = await prisma.player.update(args);
461	        return this.sanitizePlayerName(player);
462	    }
463	
464	    /**
465	     * Anonymises a player record by its unique identifier.
466	     *
467	     * This validates the provided id, then updates the player to mark them as
468	     * anonymous, clears identifying fields (name and accountEmail), and sets
469	     * the finished timestamp to now.
470	     *
471	     * @param id - The unique identifier of the player to anonymise.
472	     * @returns A Promise that resolves to the updated PlayerType.
473	     * @throws {ZodError} If the id fails schema validation via
474	     * PlayerWhereUniqueInputObjectSchema.
475	     * @throws {Error} If the database update operation fails (e.g. Prisma
476	     * errors).
477	     */
478	    async anonymise(id: number): Promise<PlayerDisplayType> {
479	        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
480	        const data = {
481	            anonymous: true,
482	            name: null,
483	            accountEmail: null,
484	            finished: new Date(),
485	        };
486	
487	        const player = await prisma.player.update({ where, data });
488	        return this.sanitizePlayerName(player);
489	    }
490	
491	    /**
492	     * Set or clear the finished timestamp for a player.
493	     *
494	     * @param playerId - The unique identifier of the player to update.
495	     * @param finished - If true (default), sets the `finished` field to the
496	     * current date/time; if false, clears the `finished` field (sets it to
497	     * null).
498	     * @returns A Promise that resolves to the updated PlayerType.
499	     * @throws Will throw if input validation or the database update fails.
500	     */
501	    async setFinished(playerId: number, finished = true): Promise<PlayerDisplayType> {
502	        const where = PlayerWhereUniqueInputObjectSchema.parse({ id: playerId });
503	        const data = {
504	            finished: finished ? new Date() : null,
505	        };
506	
507	        const player = await prisma.player.update({ where, data });
508	        return this.sanitizePlayerName(player);
509	    }
510	
511	    /**
512	     * Deletes a player by id.
513	     *
514	     * Not-found deletes (`P2025`) are treated as no-ops.
515	     *
516	     * @param id - The player id.
517	     * @returns Resolves when deletion handling completes.
518	     * @throws {z.ZodError} If id validation fails.
519	     * @throws {Error} If Prisma delete fails for reasons other than not-found.
520	     */
521	    async delete(id: number): Promise<void> {
522	        try {
523	            const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
524	            await prisma.player.delete({ where });
525	        } catch (error) {
526	            if (isPrismaNotFoundError(error)) {
527	                return;
528	            }
529	            throw error;
530	        }
531	    }
532	
533	    /**
534	     * Deletes all players.
535	     * @returns Resolves when bulk deletion completes.
536	     */
537	    async deleteAll(): Promise<void> {
538	        await prisma.player.deleteMany();
539	    }
540	
541	    /**
542	     * Builds a hierarchical family tree of players based on the `introducedBy`
543	     * relationship.
544	     *
545	     * Only players who have played at least one game (an outcome with a
546	     * non-null team) are included. Players who have never played are skipped,
547	     * but their place in the introducer chain is preserved: each played
548	     * player's effective parent is the nearest ancestor in the `introducedBy`
549	     * chain who has also played.
550	     *
551	     * After computing effective parents, the tree is further pruned to players
552	     * who either have an effective parent or are themselves the effective
553	     * introducer of at least one other played player. Played players with no
554	     * connection to anyone else are excluded.
555	     *
556	     * A single founder is identified as the first played player with no
557	     * effective parent who is also an effective introducer. Any remaining
558	     * parentless players (orphans) are attached as children of the founder.
559	     *
560	     * If no founder can be identified (e.g. the data contains only circular
561	     * references or no connections at all), an empty virtual root node named
562	     * "Toastboy FC" is returned with no children.
563	     *
564	     * @returns A promise resolving to a single {@link FamilyTreeNodeType} root
565	     * node whose children form the complete introduction tree.
566	     */
567	    async getFamilyTree(): Promise<FamilyTreeNodeType> {
568	        const [allPlayers, playedRows] = await Promise.all([
569	            prisma.player.findMany({
570	                select: {
571	                    id: true,
572	                    name: true,
573	                    anonymous: true,
574	                    introducedBy: true,
575	                },
576	            }),
577	            prisma.outcome.findMany({
578	                where: { team: { not: null } },
579	                select: { playerId: true },
580	                distinct: ['playerId'],
581	            }),
582	        ]);
583	
584	        /** Set of player IDs who have actually played at least one game. */
585	        const playedIds = new Set(playedRows.map((r) => r.playerId));
586	
587	        /**
588	         * Lookup from any player ID to their introducedBy value, used to
589	         * walk up the chain past removed (non-played) players.
590	         */
591	        const introducedByMap = new Map(
592	            allPlayers.map((p) => [p.id, p.introducedBy]),
593	        );
594	
595	        /** Only keep players who have played at least one game. */
596	        const playedPlayers = allPlayers.filter((p) => playedIds.has(p.id));
597	
598	        /**
599	         * For each played player, compute the effective parent: the
600	         * nearest ancestor in the introducer chain who has also played.
601	         */
602	        const effectiveParent = new Map<number, number | null>();
603	        for (const p of playedPlayers) {
604	            let parentId = p.introducedBy;
605	            while (parentId !== null && !playedIds.has(parentId)) {
606	                parentId = introducedByMap.get(parentId) ?? null;
607	            }
608	            effectiveParent.set(p.id, parentId);
609	        }
610	
611	        /**
612	         * Set of played player IDs that are the effective introducer of
613	         * at least one other played player.
614	         */
615	        const introducerIds = new Set(
616	            [...effectiveParent.values()].filter(
617	                (id): id is number => id !== null,
618	            ),
619	        );
620	
621	        /**
622	         * Keep played players who have an effective parent, or who are
623	         * themselves an effective introducer. Excludes played players
624	         * with no connection to anyone else in the tree.
625	         */
626	        const players = playedPlayers.filter(
627	            (p) =>
628	                effectiveParent.get(p.id) !== null ||
629	                introducerIds.has(p.id),
630	        );
631	
632	        /** Map from player id to their tree node. */
