import prisma from 'prisma/prisma';
import { PlayerType } from 'prisma/zod/schemas/models/Player.schema';
import { PlayerLoginWhereUniqueInputObjectSchema } from 'prisma/zod/schemas/objects/PlayerLoginWhereUniqueInput.schema';
import { PlayerWhereUniqueInputObjectSchema } from 'prisma/zod/schemas/objects/PlayerWhereUniqueInput.schema';
import z from 'zod';

import { isPrismaNotFoundError } from '@/lib/prismaErrors';
import { FamilyTreeNodeType, PlayerDataType, PlayerFormType } from '@/types';
import {
    PlayerCreateOneStrictSchema,
    type PlayerCreateWriteInput,
    PlayerCreateWriteInputSchema,
    PlayerUpdateOneStrictSchema,
    type PlayerUpdateWriteInput,
    PlayerUpdateWriteInputSchema,
} from '@/types/PlayerStrictSchema';
import { PointsSchema, type PointsValue } from '@/types/Points';

export type PlayerDisplayType = Omit<PlayerType, 'name'> & { name: string };
export type PlayerDataDisplayType = Omit<PlayerDataType, 'name'> & { name: string };

class PlayerService {
    /**
     * Gets the display name for a player.
     *
     * If the player is anonymous (i.e., the `anonymous` flag is `true`),
     * returns a generic name with the player ID. Otherwise, returns the
     * player's trimmed name, falling back to a generic name if the name is
     * empty or null. A `null` value for `anonymous` is treated as not anonymous
     * (equivalent to `false`).
     *
     * @param player - The player object containing id, name, and anonymous flag
     * @param player.id - The unique identifier for the player
     * @param player.name - The player's name, can be null
     * @param player.anonymous - Whether the player is anonymous; `true` marks
     * the player as anonymous, while `false` or a `null` value are treated as
     * not anonymous
     * @returns The display name for the player
     */
    private getDisplayName(player: { id: number; name: string | null; anonymous: boolean | null }) {
        if (player.anonymous) {
            return `Player ${player.id}`;
        }

        return player.name?.trim() ?? `Player ${player.id}`;
    }

    /**
    * Sanitizes a player object by replacing its name with a display name.
    *
    * @template T - The player object type extending an object with `id`,
    * `name`, and `anonymous` properties.
    * @param player - The player object to sanitize.
    * @returns A new object with the same properties as the input player, but
    * with the `name` property replaced by the display name (guaranteed to be a
    * string, not null).
    */
    private sanitizePlayerName<T extends { id: number; name: string | null; anonymous: boolean | null }>(
        player: T,
    ): Omit<T, 'name'> & { name: string } {
        return {
            ...player,
            name: this.getDisplayName(player),
        };
    }

    /**
     * Get a single player by id
     * @param id The numeric ID for the player
     * @returns A promise that resolves to the player or undefined if none was
     * found
     */
    async getById(id: number): Promise<PlayerDisplayType | null> {
        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
        const player = await prisma.player.findUnique({ where });
        return player ? this.sanitizePlayerName(player) : null;
    }

    /**
     * Get a single player by id, including email data (account email and extra emails).
     * @param id The numeric ID for the player
     * @returns A promise that resolves to the player with email data, or null if not found
     */
    async getDataById(id: number): Promise<PlayerDataDisplayType | null> {
        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
        const player = await prisma.player.findUnique({
            where,
            include: {
                extraEmails: {
                    orderBy: [
                        { verifiedAt: 'desc' },
                        { createdAt: 'desc' },
                    ],
                },
            },
        });
        if (!player) return null;

        const { extraEmails, ...rest } = player;
        const accountEmail = (rest as { accountEmail?: string | null }).accountEmail ?? null;
        const playerData = {
            ...rest,
            accountEmail,
            extraEmails,
            firstResponded: null,
            lastResponded: null,
            firstPlayed: null,
            lastPlayed: null,
            gamesPlayed: 0,
            gamesWon: 0,
            gamesDrawn: 0,
            gamesLost: 0,
        } satisfies PlayerDataType;

        return this.sanitizePlayerName(playerData);
    }

    /**
     * Get a single player by login
     * @param login The login name
     * @returns A promise that resolves to the player or undefined if none was
     * found
     */
    async getByLogin(login: string): Promise<PlayerDisplayType | null> {
        const where = PlayerLoginWhereUniqueInputObjectSchema.parse({ login });
        const playerLogin = await prisma.playerLogin.findUnique({
            where,
            include: {
                player: true,
            },
        });

        return playerLogin?.player ? this.sanitizePlayerName(playerLogin.player) : null;
    }

    /**
     * Get the player corresponding to the given string. If idOrLogin is a
     * string then we check whether a player with the given login exists. If
     * it's a number then we look up the player with that id.
     * @param idOrLogin A string which may contain a player id or a login
     * @returns A promise resolving to the player identified by idOrLogin if
     * such a player exists, or undefined otherwise.
     */
    async getByIdOrLogin(idOrLogin: string): Promise<PlayerDisplayType | null> {
        if (!isNaN(Number(idOrLogin))) {
            return this.getById(Number(idOrLogin));
        } else {
            return this.getByLogin(idOrLogin);
        }
    }

    /**
     * Get the player login corresponding to the given string. If idOrLogin is a
     * string then we check whether a player with the given login exists. If it's a
     * number then we look up the player with that id.
     * @param idOrLogin A string which may contain a player id or a login
     * @returns A string containing the login of the player identified by idOrLogin
     * if such a player exists, or undefined otherwise.
     */
    async getLogin(idOrLogin: string) {
        if (!isNaN(Number(idOrLogin))) {
            const playerLogin = await prisma.playerLogin.findFirst({
                where: {
                    playerId: Number(idOrLogin),
                },
                orderBy: {
                    login: 'asc',
                },
            });
            return playerLogin ? playerLogin.login : null;
        }

        const where = PlayerLoginWhereUniqueInputObjectSchema.parse({ login: idOrLogin });
        const playerLogin = await prisma.playerLogin.findUnique({ where });
        return playerLogin ? playerLogin.login : null;
    }

    /**
     * Retrieves the ID of a player based on the provided ID or login. If the
     * input is a valid number, it retrieves the player by ID. If the input is a
     * string, it retrieves the player by login.
     * @param idOrLogin - The ID or login of the player.
     * @returns A Promise that resolves to the player's ID if found, or null if
     * not found.
     * @throws If there is an error retrieving the player's ID.
     */
    async getId(idOrLogin: string) {
        if (!isNaN(Number(idOrLogin))) {
            const player = await this.getById(Number(idOrLogin));
            return player ? player.id : null;
        } else {
            const where = PlayerLoginWhereUniqueInputObjectSchema.parse({ login: idOrLogin });
            const playerLogin = await prisma.playerLogin.findUnique({ where });
            return playerLogin ? playerLogin.playerId : null;
        }
    }

    /**
     * Retrieves the player with the next-lowest ID (i.e. the previous player by
     * ID).
     * @param playerId - The ID of the current player.
     * @returns A promise that resolves to the previous player if found, or null
     * if not found.
     */
    async getPrevious(playerId: number): Promise<PlayerDisplayType | null> {
        const id = z.coerce.number().int().min(1).parse(playerId);

        const player = await prisma.player.findFirst({
            where: {
                id: {
                    lt: id,
                },
            },
            orderBy: {
                id: 'desc',
            },
        });
        return player ? this.sanitizePlayerName(player) : null;
    }

    /**
     * Retrieves the player with the next-highest ID (i.e. the next player by
     * ID).
     * @param playerId - The ID of the current player.
     * @returns A promise that resolves to the next player if found, or null
     * if not found.
     */
    async getNext(playerId: number): Promise<PlayerDisplayType | null> {
        const id = z.coerce.number().int().min(1).parse(playerId);

        const player = await prisma.player.findFirst({
            where: {
                id: {
                    gt: id,
                },
            },
            orderBy: {
                id: 'asc',
            },
        });
        return player ? this.sanitizePlayerName(player) : null;
    }

    /**
     * Retrieves all players from the database with their outcomes and extra
     * emails.
     *
     * @param active - Optional filter to only return active players (those
     * without a finished date). Defaults to undefined for all players.
     * @returns A promise that resolves to an array of PlayerDataType objects
     * enriched with computed statistics including:
     *          - accountEmail: The player's account email address
     *          - firstResponded: The earliest gameDayId where the player responded
     *          - lastResponded: The latest gameDayId where the player responded
     *          - firstPlayed: The earliest gameDayId where the player earned points
     *          - lastPlayed: The latest gameDayId where the player earned points
     *          - gamesPlayed: Total number of games with recorded points
     *          - gamesWon: Number of games where the player earned 3 points
     *          - gamesDrawn: Number of games where the player earned 1 point
     *          - gamesLost: Number of games where the player earned 0 points
     * @throws Logs and re-throws any errors that occur during the database
     * query
     */
    async getAll(options?: { activeOnly?: boolean }): Promise<PlayerDataDisplayType[]> {
        const players = await prisma.player.findMany({
            where: options?.activeOnly ? { finished: null } : undefined,
            include: {
                outcomes: {
                    orderBy: {
                        gameDayId: 'desc',
                    },
                },
                extraEmails: {
                    orderBy: [
                        { verifiedAt: 'desc' },
                        { createdAt: 'desc' },
                    ],
                },
            },
        });

        return players.map(({ outcomes, ...player }) => {
            const gamesResponded = outcomes.filter(outcome => outcome.response !== null);
            const gamesPlayed = outcomes.filter(outcome => outcome.points !== null);

            const respondedGameDays = gamesResponded.map(outcome => outcome.gameDayId);
            const playedGameDays = gamesPlayed.map(outcome => outcome.gameDayId);

            const accountEmail = (player as { accountEmail?: string | null }).accountEmail ?? null;

            const playerWithComputedFields = {
                ...player,
                accountEmail,
                firstResponded: respondedGameDays.length > 0 ? Math.min(...respondedGameDays) : null,
                lastResponded: respondedGameDays.length > 0 ? Math.max(...respondedGameDays) : null,
                firstPlayed: playedGameDays.length > 0 ? Math.min(...playedGameDays) : null,
                lastPlayed: playedGameDays.length > 0 ? Math.max(...playedGameDays) : null,
                gamesPlayed: gamesPlayed.length,
                gamesWon: gamesPlayed.filter(outcome => outcome.points === 3).length,
                gamesDrawn: gamesPlayed.filter(outcome => outcome.points === 1).length,
                gamesLost: gamesPlayed.filter(outcome => outcome.points === 0).length,
            } satisfies PlayerDataType;

            return this.sanitizePlayerName(playerWithComputedFields);
        });
    }

    /**
     * Retrieves all player IDs and logins from the database.
     *
     * @returns {Promise<string[]>} A promise that resolves to an array of strings containing player IDs and logins.
     * @throws Will throw an error if there is an issue fetching the player data.
     */
    async getAllIdsAndLogins() {
        const players = await prisma.player.findMany({
            select: {
                id: true,
                logins: {
                    select: {
                        login: true,
                    },
                    orderBy: {
                        login: 'asc',
                    },
                },
            },
        });
        const idsAndLogins: string[] = [];

        players.forEach((player) => {
            idsAndLogins.push(player.id.toString());
            player.logins.forEach((login) => {
                idsAndLogins.push(login.login);
            });
        });

        return idsAndLogins;
    }

    /**
     * Retrieves the form of a player for a given game day, based on their previous outcomes.
     * @param playerId - The ID of the player.
     * @param gameDayId - The ID of the game day to consider, or 0 for the latest.
     * @param history - The number of previous outcomes to consider.
     * @returns A promise that resolves to an array of outcomes with game days.
     */
    async getForm(
        playerId: number,
        gameDayId: number,
        history: number,
    ): Promise<PlayerFormType[]> {
        return prisma.outcome.findMany({
            where: {
                gameDayId: gameDayId !== 0 ? { lt: gameDayId } : {},
                playerId: playerId,
                points: {
                    not: null,
                },
            },
            orderBy: {
                gameDayId: 'desc',
            },
            take: history,
            include: {
                gameDay: true,
            },
        });
    }

    /**
     * Retrieves the most recent outcome for a player, optionally filtered by
     * year and/or points value.
     *
     * @param playerId - The unique identifier of the player.
     * @param year - An optional year to limit the search range.
     * @param points - An optional points filter: if provided, only outcomes
     * with this points value will be returned. If not, the most recent outcome
     * with any non-null points value will be returned.
     * @returns A promise that resolves to the player's latest outcome including
     * its game day, or `null` if none is found.
     * @throws Will propagate any errors encountered during the retrieval
     * process.
     */
    async getLastResult(playerId: number, year?: number, points?: PointsValue): Promise<PlayerFormType | null> {
        const id = z.coerce.number().int().min(1).parse(playerId);
        const validatedPoints = PointsSchema.optional().parse(points);

        return prisma.outcome.findFirst({
            where: {
                playerId: id,
                points: validatedPoints ?? { not: null },
                gameDay: {
                    date: {
                        gte: year ? new Date(Date.UTC(year, 0, 1)) : undefined,
                        lt: year ? new Date(Date.UTC(year + 1, 0, 1)) : undefined,
                    },
                },
            },
            orderBy: {
                gameDayId: 'desc',
            },
            include: {
                gameDay: true,
            },
            take: 1,
        });
    }

    /**
     * Retrieves all the years that the given player has participated in any
     * way. That could be just responding to an invitation, going to the pub, or
     * playing a game of course.
     * @returns A promise that resolves to an array of distinct years: this will
     * always include 0 for 'all time' if there's at least one active year.
     * @throws An error if there is a failure.
     */
    async getYearsActive(playerId: number): Promise<number[]> {
        const id = z.coerce.number().int().min(1).parse(playerId);

        const outcomes = await prisma.outcome.findMany({
            where: {
                playerId: id,
            },
            include: {
                gameDay: true,
            },
        });
        const years = outcomes.map(o => o.gameDay.date.getFullYear());
        const distinctYears = Array.from(new Set(years));
        if (distinctYears.length) {
            distinctYears.push(0);
        }

        return distinctYears;
    }

    /**
     * Creates a player from validated write input.
     * @param data - Player write payload.
     * @returns The created player row.
     */
    async create(data: PlayerCreateWriteInput): Promise<PlayerDisplayType> {
        const writeData = PlayerCreateWriteInputSchema.parse(data);
        const args = PlayerCreateOneStrictSchema.parse({ data: writeData });
        const player = await prisma.player.create(args);
        return this.sanitizePlayerName(player);
    }

    /**
     * Updates an existing player by id from validated write input.
     * @param data - Player write payload including `id` and update fields.
     * @returns The updated player row.
     */
    async update(data: PlayerUpdateWriteInput): Promise<PlayerDisplayType> {
        const { id, ...updateData } = PlayerUpdateWriteInputSchema.parse(data);
        const args = PlayerUpdateOneStrictSchema.parse({
            where: { id },
            data: updateData,
        });
        const player = await prisma.player.update(args);
        return this.sanitizePlayerName(player);
    }

    /**
     * Anonymises a player record by its unique identifier.
     *
     * This validates the provided id, then updates the player to mark them as
     * anonymous, clears identifying fields (name and accountEmail), and sets
     * the finished timestamp to now.
     *
     * @param id - The unique identifier of the player to anonymise.
     * @returns A Promise that resolves to the updated PlayerType.
     * @throws {ZodError} If the id fails schema validation via
     * PlayerWhereUniqueInputObjectSchema.
     * @throws {Error} If the database update operation fails (e.g. Prisma
     * errors).
     */
    async anonymise(id: number): Promise<PlayerDisplayType> {
        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
        const data = {
            anonymous: true,
            name: null,
            accountEmail: null,
            finished: new Date(),
        };

        const player = await prisma.player.update({ where, data });
        return this.sanitizePlayerName(player);
    }

    /**
     * Set or clear the finished timestamp for a player.
     *
     * @param playerId - The unique identifier of the player to update.
     * @param finished - If true (default), sets the `finished` field to the
     * current date/time; if false, clears the `finished` field (sets it to
     * null).
     * @returns A Promise that resolves to the updated PlayerType.
     * @throws Will throw if input validation or the database update fails.
     */
    async setFinished(playerId: number, finished = true): Promise<PlayerDisplayType> {
        const where = PlayerWhereUniqueInputObjectSchema.parse({ id: playerId });
        const data = {
            finished: finished ? new Date() : null,
        };

        const player = await prisma.player.update({ where, data });
        return this.sanitizePlayerName(player);
    }

    /**
     * Deletes a player by id.
     *
     * Not-found deletes (`P2025`) are treated as no-ops.
     *
     * @param id - The player id.
     * @returns Resolves when deletion handling completes.
     * @throws {z.ZodError} If id validation fails.
     * @throws {Error} If Prisma delete fails for reasons other than not-found.
     */
    async delete(id: number): Promise<void> {
        try {
            const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
            await prisma.player.delete({ where });
        } catch (error) {
            if (isPrismaNotFoundError(error)) {
                return;
            }
            throw error;
        }
    }

    /**
     * Deletes all players.
     * @returns Resolves when bulk deletion completes.
     */
    async deleteAll(): Promise<void> {
        await prisma.player.deleteMany();
    }

    /**
     * Builds a hierarchical family tree of players based on the `introducedBy`
     * relationship.
     *
     * Only players who have played at least one game (an outcome with a
     * non-null team) are included. Players who have never played are skipped,
     * but their place in the introducer chain is preserved: each played
     * player's effective parent is the nearest ancestor in the `introducedBy`
     * chain who has also played.
     *
     * After computing effective parents, the tree is further pruned to players
     * who either have an effective parent or are themselves the effective
     * introducer of at least one other played player. Played players with no
     * connection to anyone else are excluded.
     *
     * A single founder is identified as the first played player with no
     * effective parent who is also an effective introducer. Any remaining
     * parentless players (orphans) are attached as children of the founder.
     *
     * If no founder can be identified (e.g. the data contains only circular
     * references or no connections at all), an empty virtual root node named
     * "Toastboy FC" is returned with no children.
     *
     * @returns A promise resolving to a single {@link FamilyTreeNodeType} root
     * node whose children form the complete introduction tree.
     */
    async getFamilyTree(): Promise<FamilyTreeNodeType> {
        const [allPlayers, playedRows] = await Promise.all([
            prisma.player.findMany({
                select: {
                    id: true,
                    name: true,
                    anonymous: true,
                    introducedBy: true,
                },
            }),
            prisma.outcome.findMany({
                where: { team: { not: null } },
                select: { playerId: true },
                distinct: ['playerId'],
            }),
        ]);

        /** Set of player IDs who have actually played at least one game. */
        const playedIds = new Set(playedRows.map((r) => r.playerId));

        /**
         * Lookup from any player ID to their introducedBy value, used to
         * walk up the chain past removed (non-played) players.
         */
        const introducedByMap = new Map(
            allPlayers.map((p) => [p.id, p.introducedBy]),
        );

        /** Only keep players who have played at least one game. */
        const playedPlayers = allPlayers.filter((p) => playedIds.has(p.id));

        /**
         * For each played player, compute the effective parent: the
         * nearest ancestor in the introducer chain who has also played.
         */
        const effectiveParent = new Map<number, number | null>();
        for (const p of playedPlayers) {
            let parentId = p.introducedBy;
            while (parentId !== null && !playedIds.has(parentId)) {
                parentId = introducedByMap.get(parentId) ?? null;
            }
            effectiveParent.set(p.id, parentId);
        }

        /**
         * Set of played player IDs that are the effective introducer of
         * at least one other played player.
         */
        const introducerIds = new Set(
            [...effectiveParent.values()].filter(
                (id): id is number => id !== null,
            ),
        );

        /**
         * Keep played players who have an effective parent, or who are
         * themselves an effective introducer. Excludes played players
         * with no connection to anyone else in the tree.
         */
        const players = playedPlayers.filter(
            (p) =>
                effectiveParent.get(p.id) !== null ||
                introducerIds.has(p.id),
        );

        /** Map from player id to their tree node. */
        const nodeMap = new Map<number, FamilyTreeNodeType>();
        for (const p of players) {
            nodeMap.set(p.id, {
                id: p.id,
                name: this.getDisplayName(p),
                children: [],
            });
        }

        /**
         * Identify the founder: the played player with no effective
         * parent who is also an introducer. Any other orphan players
         * are attached under the founder.
         */
        const orphanIds: number[] = [];
        let founderId: number | null = null;
        for (const p of players) {
            if (effectiveParent.get(p.id) === null) {
                if (introducerIds.has(p.id) && founderId === null) {
                    founderId = p.id;
                } else {
                    orphanIds.push(p.id);
                }
            }
        }

        /** Build the tree by attaching children to parents. */
        for (const p of players) {
            const node = nodeMap.get(p.id)!;
            const parentId = effectiveParent.get(p.id) ?? null;

            if (parentId !== null && nodeMap.has(parentId)) {
                nodeMap.get(parentId)!.children.push(node);
            }
        }

        /**
         * If a founder was found, attach remaining orphans under them
         * and return the founder's node as the tree root.
         */
        if (founderId !== null) {
            const founderNode = nodeMap.get(founderId)!;
            for (const id of orphanIds) {
                founderNode.children.push(nodeMap.get(id)!);
            }
            return founderNode;
        }

        /** Fallback: circular references or no connections — return virtual root. */
        return { id: 0, name: 'Toastboy FC', children: [] };
    }
}

const playerService = new PlayerService();
export default playerService;

import * as z from 'zod';

export const PlayerSchema = z.object({
  id: z.number().int(),
  name: z.string().nullish(),
  accountEmail: z.string().nullish(),
  anonymous: z.boolean().nullish(),
  goalie: z.boolean().nullish(),
  joined: z.date().nullish(),
  finished: z.date().nullish(),
  born: z.number().int().nullish(),
  comment: z.string().nullish(),
  introducedBy: z.number().int().nullish(),
});

export type PlayerType = z.infer<typeof PlayerSchema>;

