export const PlayerProfile = ({
    player,
    year,
    introducedBy,
    history,
    lastPlayed,
    lastWon,
    clubs,
    countries,
    arse,
    activeYears,
    record,
    trophies,
    prevPlayer,
    nextPlayer,
    isAuthenticated = false,
    isAdmin = false,
    playerData,
    onSendEmail,
